import hashlib
import hmac
import binascii


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    # Ensure the certificate is in bytes for hashing
    if isinstance(certificate, str):
        certificate = certificate.encode('utf-8')

    # Compute the SHA-256 hash of the certificate
    computed_hash = hashlib.sha256(certificate).digest()

    # Handle known_hash if it is provided as a hex string
    if isinstance(known_hash, str):
        try:
            known_hash_bytes = binascii.unhexlify(known_hash)
        except (binascii.Error, ValueError):
            return False
    elif isinstance(known_hash, bytes):
        known_hash_bytes = known_hash
    else:
        # If known_hash is neither string nor bytes, it cannot match
        return False

    # Use hmac.compare_digest to prevent timing attacks (CWE-208)
    return hmac.compare_digest(computed_hash, known_hash_bytes)

import secrets

def getSessionID():
    '''
    Return a random and unique session ID.
    '''
    return secrets.token_urlsafe(32)

import pickle


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return pickle.dumps(payload)

